A generator function uses yield instead of return, producing values lazily one at a time. The caller gets an iterator; values are computed only when requested. Memory stays bounded to one item (or batch) at a time.

def read_csv_chunks(path, batch_size=1000):
    with open(path, newline='') as f:
        import csv
        reader = csv.DictReader(f)
        batch = []
        for row in reader:
            batch.append(row)
            if len(batch) >= batch_size:
                yield batch
                batch = []
        if batch:  # flush remaining rows
            yield batch

# Chain generators for pipeline composition:
def filter_active(batches):
    for batch in batches:
        yield [r for r in batch if r['status'] == 'active']

def transform(batches):
    for batch in batches:
        yield [{'id': r['id'], 'rev': float(r['revenue'])} for r in batch]

# Compose without materializing intermediate results:
for batch in transform(filter_active(read_csv_chunks('large.csv'))):
    load_to_db(batch)

yield from delegates to a sub-generator: yield from sub_gen() is equivalent to for item in sub_gen(): yield item, but also handles send() and throw() correctly. Use it to flatten nested generators or compose pipeline stages.
